content:
NVC Transformation Tool

body {
font-family: Arial, sans-serif;
margin: 0;
padding: 0;
display: flex;
justify-content: center;
align-items: center;
min-height: 100vh;
background-color: #f9f9f9;
}
.container {
background: white;
padding: 2em;
border-radius: 12px;
box-shadow: 0 4px 8px rgba(0, 0, 0, 0.1);
max-width: 600px;
width: 100%;
}
h1 {
font-size: 1.8rem;
text-align: center;
margin-bottom: 1em;
}
label {
display: block;
margin-bottom: 0.5em;
font-weight: bold;
}
textarea {
width: 100%;
height: 120px;
padding: 10px;
border: 1px solid #ccc;
border-radius: 8px;
margin-bottom: 1em;
resize: none;
font-size: 1rem;
}
button {
background-color: #4CAF50;
color: white;
border: none;
padding: 0.75em 1.5em;
font-size: 1rem;
border-radius: 8px;
cursor: pointer;
width: 100%;
}
button:hover {
background-color: #45a049;
}
.result {
margin-top: 1em;
padding: 1em;
background: #f1f1f1;
border-radius: 8px;
}

function transformToNVC() {
const inputText = document.getElementById('userInput').value.trim();
if (!inputText) {
alert("Please enter some text.");
return;
}
// Placeholder logic for NVC transformation
const transformedText = `Observation: I noticed you said, "${inputText}".
Feeling: This made me feel curious.
Need: I value clarity and understanding.
Request: Could you clarify what you meant by that?`;
document.getElementById('result').textContent = transformedText;
}

